/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * <Replace with your name(s) and NetID(s).>
 */

#include <assert.h>
#include <pthread.h>

#include "csapp.h"

/* Connection entry to pass to thread pool */
typedef struct {
	int connfd;
	struct sockaddr_in clientaddr;
} connent_t;

/* Thread pool buffer for concurrent request handling */
typedef struct {
	connent_t *buf;		/* Buffer of connection entries */
	int n;			/* Maximum number of slots */
	int front;		/* Index of first item */
	int rear;		/* Index of next free item */
	int count;		/* Number of items in buffer */
	pthread_mutex_t mutex;		/* Protects accesses to buf */
	pthread_cond_t not_full;	/* Signaled when buffer is not full */
	pthread_cond_t not_empty;	/* Signaled when buffer is not empty */
} sbuf_t;

static void	client_error(int fd, const char *cause, int err_num,
		    const char *short_msg, const char *long_msg);
static char    *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int	parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);

/* Forward declarations */
static void doit(int fd, struct sockaddr_in *clientaddr);
static void *thread_routine(void *vargp);
static void sbuf_init(sbuf_t *sp, int n);
static void sbuf_insert(sbuf_t *sp, int connfd, struct sockaddr_in *clientaddr);
static connent_t sbuf_remove(sbuf_t *sp);

/* Constants */
#define SBUF_SIZE 16

/* Global variables */
static FILE *logfile;		/* Log file */
static pthread_mutex_t log_mutex;	/* Mutex for log file access */
static sbuf_t sbuf;		/* Shared buffer for thread pool */

/*
 * Requires:
 *   argc == 2 and argv[1] is a valid port number
 *
 * Effects:
 *   Starts a web proxy server listening on the given port.
 *   Uses a prethreaded pool approach to handle concurrent clients.
 */
int
main(int argc, char **argv)
{
	int listenfd, connfd;
	socklen_t clientlen;
	struct sockaddr_in clientaddr;
	int i;
	pthread_t tid;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	/* Ignore SIGPIPE to prevent crash when writing to closed connection */
	Signal(SIGPIPE, SIG_IGN);

	/* Open log file */
	logfile = Fopen("proxy.log", "a");
	pthread_mutex_init(&log_mutex, NULL);

	/* Create listening socket */
	listenfd = open_listenfd(argv[1]);

	/* Initialize the shared buffer */
	sbuf_init(&sbuf, SBUF_SIZE);

	/* Create pool threads */
	for (i = 0; i < 4; i++) {
		Pthread_create(&tid, NULL, thread_routine, NULL);
	}

	/* Main server loop */
	while (1) {
		clientlen = sizeof(clientaddr);
		connfd = accept(listenfd, (SA *)&clientaddr, &clientlen);
		if (connfd < 0) {
			if (errno != EINTR) {
				perror("accept");
			}
			continue;
		}
		sbuf_insert(&sbuf, connfd, &clientaddr);
	}

	/* Return success. */
	return (0);
}

/*
 * Requires:
 *   sp is a pointer to a buffer with n slots, and n is positive.
 *
 * Effects:
 *   Initializes the buffer sp with n slots.
 */
static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf = Malloc(n * sizeof(connent_t));
	sp->n = n;
	sp->front = sp->rear = 0;
	sp->count = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->not_full, NULL);
	pthread_cond_init(&sp->not_empty, NULL);
}

/*
 * Requires:
 *   sp is a pointer to a buffer initialized with sbuf_init.
 *   connfd is a connected socket descriptor.
 *   clientaddr points to the client's socket address.
 *
 * Effects:
 *   Inserts connection onto the rear of the buffer sp.
 */
static void
sbuf_insert(sbuf_t *sp, int connfd, struct sockaddr_in *clientaddr)
{
	pthread_mutex_lock(&sp->mutex);
	/* Wait until buffer is not full */
	while (sp->count >= sp->n)
		pthread_cond_wait(&sp->not_full, &sp->mutex);
	/* Insert item */
	sp->buf[sp->rear].connfd = connfd;
	sp->buf[sp->rear].clientaddr = *clientaddr;
	sp->rear = (sp->rear + 1) % sp->n;
	sp->count++;
	/* Signal that buffer is not empty */
	pthread_cond_signal(&sp->not_empty);
	pthread_mutex_unlock(&sp->mutex);
}

/*
 * Requires:
 *   sp is a pointer to a buffer initialized with sbuf_init.
 *
 * Effects:
 *   Removes and returns the first connection from buffer sp.
 */
static connent_t
sbuf_remove(sbuf_t *sp)
{
	connent_t item;

	pthread_mutex_lock(&sp->mutex);
	/* Wait until buffer is not empty */
	while (sp->count == 0)
		pthread_cond_wait(&sp->not_empty, &sp->mutex);
	/* Remove item */
	item = sp->buf[sp->front];
	sp->front = (sp->front + 1) % sp->n;
	sp->count--;
	/* Signal that buffer is not full */
	pthread_cond_signal(&sp->not_full);
	pthread_mutex_unlock(&sp->mutex);
	return (item);
}

/*
 * Requires:
 *   vargp is NULL.
 *
 * Effects:
 *   Thread routine that handles client connections from the buffer.
 */
static void *
thread_routine(void *vargp)
{
	connent_t item;

	(void)vargp;	/* Avoid unused parameter warning */
	Pthread_detach(pthread_self());

	while (1) {
		item = sbuf_remove(&sbuf);
		doit(item.connfd, &item.clientaddr);
		Close(item.connfd);
	}

	return (NULL);
}

/*
 * Requires:
 *   fd is an open socket connected to the client,
 *   clientaddr points to the client's socket address.
 *
 * Effects:
 *   Handles a single HTTP client request:
 *   - Reads the HTTP request from the client
 *   - Parses the URI
 *   - Connects to the server
 *   - Forwards the request
 *   - Receives and forwards the response
 *   - Logs the transaction
 */
static void
doit(int fd, struct sockaddr_in *clientaddr)
{
	char buf[MAXBUF], method[MAXLINE], uri[MAXLINE], version[MAXLINE];
	char hostname[MAXLINE], port[MAXLINE], pathname[MAXLINE];
	char *hostnamep, *portp, *pathnamep;
	rio_t rio_client, rio_server;
	int server_fd;
	int response_size = 0;
	char line[MAXLINE];
	char request[MAXBUF];
	ssize_t nread;

	/* Read the request from client */
	rio_readinitb(&rio_client, fd);

	/* Read the first line of the request */
	if ((nread = rio_readlineb(&rio_client, buf, MAXBUF)) <= 0) {
		return;
	}

	/* Parse the request line */
	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
		client_error(fd, "Malformed request", 400, "Bad Request",
		    "Request line is malformed");
		return;
	}

	/* Only support GET */
	if (strcasecmp(method, "GET") != 0) {
		client_error(fd, "Method not supported", 501,
		    "Not Implemented",
		    "Proxy does not support this method");
		return;
	}

	/* Parse the URI */
	hostnamep = hostname;
	portp = port;
	pathnamep = pathname;

	if (parse_uri(uri, &hostnamep, &portp, &pathnamep) < 0) {
		client_error(fd, "Invalid URI", 400, "Bad Request",
		    "URI is invalid or not HTTP");
		Free(hostnamep);
		Free(portp);
		Free(pathnamep);
		return;
	}

	/* Connect to the server */
	server_fd = open_clientfd(hostnamep, portp);
	if (server_fd < 0) {
		client_error(fd, "Unable to connect to server", 502,
		    "Bad Gateway",
		    "Failed to connect to origin server");
		Free(hostnamep);
		Free(portp);
		Free(pathnamep);
		return;
	}

	/* Initialize RIO for server */
	rio_readinitb(&rio_server, server_fd);

	/* Build request to send to server (with path only, not full URI) */
	snprintf(request, MAXBUF, "GET %s HTTP/1.0\r\n", pathnamep);

	/* Read and forward headers from client to server, modifying as needed */
	while (1) {
		if ((nread = rio_readlineb(&rio_client, line, MAXLINE)) <= 0) {
			break;
		}

		/* Skip connection-related headers */
		if ((strncasecmp(line, "Connection:", 11) == 0) ||
		    (strncasecmp(line, "Keep-Alive:", 11) == 0) ||
		    (strncasecmp(line, "Proxy-Connection:", 16) == 0)) {
			continue;
		}

		/* Stop at empty line (end of headers) */
		if (strcmp(line, "\r\n") == 0) {
			break;
		}

		/* Forward the header to server */
		strncat(request, line, MAXBUF - strlen(request) - 1);
	}

	/* Add Connection: close header */
	strncat(request, "Connection: close\r\n", MAXBUF - strlen(request) - 1);

	/* Add final CRLF to complete headers */
	strncat(request, "\r\n", MAXBUF - strlen(request) - 1);

	/* Send the request to the server */
	if (rio_writen(server_fd, request, strlen(request)) < 0) {
		/* Error writing to server; clean up and return */
		Close(server_fd);
		Free(hostnamep);
		Free(portp);
		Free(pathnamep);
		return;
	}

	/* Read response from server and forward to client */
	while ((nread = rio_readnb(&rio_server, buf, MAXBUF)) > 0) {
		if (rio_writen(fd, buf, nread) < 0) {
			/* Error writing to client; stop */
			break;
		}
		response_size += nread;
	}

	/* Log the transaction */
	char *log_entry = create_log_entry(clientaddr, uri, response_size);
	pthread_mutex_lock(&log_mutex);
	fprintf(logfile, "%s\n", log_entry);
	fflush(logfile);
	pthread_mutex_unlock(&log_mutex);
	Free(log_entry);

	/* Clean up */
	Close(server_fd);
	Free(hostnamep);
	Free(portp);
	Free(pathnamep);
}

/*
 * Requires:
 *   The parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
 *   host name, port, and path name.  Create strings containing the host name,
 *   port, and path name, and return them through the parameters "hostnamep",
 *   "portp", "pathnamep", respectively.  (The caller must free the memory
 *   storing these strings.)  Return -1 if there are any problems and 0
 *   otherwise.
 */
static int
parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
{
	const char *pathname_begin, *port_begin, *port_end;

	if (strncasecmp(uri, "http://", 7) != 0)
		return (-1);

	/* Extract the host name. */
	const char *host_begin = uri + 7;
	const char *host_end = strpbrk(host_begin, ":/ \r\n");
	if (host_end == NULL)
		host_end = host_begin + strlen(host_begin);
	int len = host_end - host_begin;
	char *hostname = Malloc(len + 1);
	strncpy(hostname, host_begin, len);
	hostname[len] = '\0';
	*hostnamep = hostname;

	/* Look for a port number.  If none is found, use port 80. */
	if (*host_end == ':') {
		port_begin = host_end + 1;
		port_end = strpbrk(port_begin, "/ \r\n");
		if (port_end == NULL)
			port_end = port_begin + strlen(port_begin);
		len = port_end - port_begin;
	} else {
		port_begin = "80";
		port_end = host_end;
		len = 2;
	}
	char *port = Malloc(len + 1);
	strncpy(port, port_begin, len);
	port[len] = '\0';
	*portp = port;

	/* Extract the path. */
	if (*port_end == '/') {
		pathname_begin = port_end;
		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
		if (pathname_end == NULL)
			pathname_end = pathname_begin + strlen(pathname_begin);
		len = pathname_end - pathname_begin;
	} else {
		pathname_begin = "/";
		len = 1;
	}
	char *pathname = Malloc(len + 1);
	strncpy(pathname, pathname_begin, len);
	pathname[len] = '\0';
	*pathnamep = pathname;

	return (0);
}

/*
 * Requires:
 *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
 *   parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Returns a string containing a properly formatted log entry.  This log
 *   entry is based upon the socket address of the requesting client
 *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
 *   the response from the server ("size").
 */
static char *
create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
{
	struct tm result;

	/*
	 * Create a large enough array of characters to store a log entry.
	 * Although the length of the URI can exceed MAXLINE, the combined
	 * lengths of the other fields and separators cannot.
	 */
	const size_t log_maxlen = MAXLINE + strlen(uri);
	char *const log_str = Malloc(log_maxlen + 1);

	/* Get a formatted time string. */
	time_t now = time(NULL);
	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
	    localtime_r(&now, &result));

	/*
	 * Convert the IP address in network byte order to dotted decimal
	 * form.
	 */
	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
	    INET_ADDRSTRLEN);
	log_strlen += strlen(&log_str[log_strlen]);

	/*
	 * Assert that the time and IP address fields occupy less than half of
	 * the space that is reserved for the non-URI fields.
	 */
	assert(log_strlen < MAXLINE / 2);

	/*
	 * Add the URI and response size onto the end of the log entry.
	 */
	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
	    size);

	return (log_str);
}

/*
 * Requires:
 *   The parameter "fd" must be an open socket that is connected to the client.
 *   The parameters "cause", "short_msg", and "long_msg" must point to properly 
 *   NUL-terminated strings that describe the reason why the HTTP transaction
 *   failed.  The string "short_msg" may not exceed 32 characters in length,
 *   and the string "long_msg" may not exceed 80 characters in length.
 *
 * Effects:
 *   Constructs an HTML page describing the reason why the HTTP transaction
 *   failed, and writes an HTTP/1.0 response containing that page as the
 *   content.  The cause appearing in the HTML page is truncated if the
 *   string "cause" exceeds 2048 characters in length.
 */
static void
client_error(int fd, const char *cause, int err_num, const char *short_msg,
    const char *long_msg)
{
	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];

	assert(strlen(short_msg) <= 32);
	assert(strlen(long_msg) <= 80);
	/* Ensure that "body" is much larger than "truncated_cause". */
	assert(sizeof(truncated_cause) < MAXBUF / 2);

	/*
	 * Create a truncated "cause" string so that the response body will not
	 * exceed MAXBUF.
	 */
	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
	truncated_cause[sizeof(truncated_cause) - 1] = '\0';

	/* Build the HTTP response body. */
	snprintf(body, MAXBUF,
	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
	    "%d: %s\r\n"
	    "<p>%s: %s\r\n"
	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
	    err_num, short_msg, long_msg, truncated_cause);

	/* Build the HTTP response headers. */
	snprintf(headers, MAXBUF,
	    "HTTP/1.0 %d %s\r\n"
	    "Content-type: text/html\r\n"
	    "Content-length: %d\r\n"
	    "\r\n",
	    err_num, short_msg, (int)strlen(body));

	/* Write the HTTP response. */
	if (rio_writen(fd, headers, strlen(headers)) != -1)
		rio_writen(fd, body, strlen(body));
}
